+                .documents
+                .iter()
+                .map(|(rowid, cols)| (*rowid, 0.0, cols.clone()))
+                .collect();
+            rows.sort_by_key(|(rowid, _, _)| *rowid);
+            self.results = rows;
         }

         Ok(())
